import{_ as a,o as s,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"19. Casual Employment","description":"","frontmatter":{"title":"19. Casual Employment","eba":"Nurses and Midwives 2024-2028","topics":["employment"]},"headers":[],"relativePath":"ebas/nurses-midwives/employment-types/19-casual-employment.md","filePath":"ebas/nurses-midwives/employment-types/19-casual-employment.md"}'),n={name:"ebas/nurses-midwives/employment-types/19-casual-employment.md"};function r(l,e,i,p,m,c){return s(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_19-casual-employment" tabindex="-1">19. Casual Employment <a class="header-anchor" href="#_19-casual-employment" aria-label="Permalink to &quot;19. Casual Employment&quot;">​</a></h1><p><strong>19.1</strong> A casual Employee is an Employee who:</p><p><strong>(a)</strong> is made an offer of employment on the basis that the Employer makes no firm advance commitment to continuing and indefinite work (e.g. relief work such as replacing an Employee on an unplanned absence); and</p><p><strong>(b)</strong> is paid in accordance with clause 19.5 of this Agreement; and</p><p><strong>(c)</strong> accepts the offer of employment on that basis; and</p><p><strong>(d)</strong> is an Employee as a result of that acceptance;</p><p><strong>19.2</strong> When determining whether an Employer has made an offer of employment in accordance with subclause 19.1(a) above, regard is to be had to the Act which presently provides for consideration of the following indicia:</p><p><strong>(a)</strong> the &quot;real substance, practical reality and a true nature of the employment relationship&quot;, including whether a firm advanced commitment has arisen by reason of:</p><p><strong>(i)</strong> the Employee&#39;s contract of employment; or</p><p><strong>(ii)</strong> a mutual understanding or expectation that has arisen between the Employer and the Employee (not rising to the level of a term of that contract or to a variation of any such term); and</p><p><strong>(b)</strong> having regard to, but not limited to, the following considerations (which may indicate the presence, rather than an absence, of such a commitment):</p><p><strong>(i)</strong> whether there is an inability of the Employer to elect to offer, or not offer, work to the Employee;</p><p><strong>(ii)</strong> whether there is an ability of the Employee to elect to accept or reject work (and whether this occurs in practice);</p><p><strong>(iii)</strong> whether, having regard to the nature of the Employer&#39;s enterprise, it is reasonably likely that there will be future availability of continuing work in that enterprise of the kind usually performed by the Employee;</p><p><strong>(iv)</strong> whether there are full-time Employees or part-time Employees performing the same kind of work in the Employer&#39;s enterprise that is usually performed by the Employee; and</p><p><strong>(v)</strong> whether there is a regular pattern of work for the Employee.</p><p><strong>19.3</strong> Subject to the minimum engagement period (or payment in lieu of), a casual Employee&#39;s engagement is terminable without prior notice by either party.</p><p><strong>19.4</strong> The minimum engagement for a casual Employee is two hours.</p><p><strong>19.5</strong> A casual Employee will be paid an hourly rate equal to 1/38th of the weekly salary for the Employee&#39;s classification plus 25%. Payments for shift work (<a href="/eba/ebas/nurses-midwives/allowances/34-shift-allowance.html">clause 34</a>), Saturdays and Sundays (<a href="/eba/ebas/nurses-midwives/hours-of-work/48-special-rates-for-saturdays-and-sundays.html">clause 48</a>), Overtime (<a href="/eba/ebas/nurses-midwives/hours-of-work/49-overtime.html">clause 49</a>) and Public Holidays (<a href="/eba/ebas/medical-specialists/leave/56-public-holidays.html">clause 56</a>) also apply to casual Employees.</p><p><strong>19.6</strong> Except where expressly excluded, a casual Employee will be entitled to receive the allowances prescribed by Part E of this Agreement.</p><p><strong>19.7</strong> The following provisions do not apply to casual Employees:</p><p><strong>(a)</strong> annual leave (<a href="/eba/ebas/nurses-midwives/leave/57-annual-leave.html">clause 57</a>);</p><p><strong>(b)</strong> purchased leave (<a href="/eba/ebas/nurses-midwives/leave/60-purchased-leave.html">clause 60</a>);</p><p><strong>(c)</strong> paid personal leave (<a href="/eba/ebas/nurses-midwives/leave/61-personal-leave.html">clause 61</a>);</p><p><strong>(d)</strong> paid compassionate leave (<a href="/eba/ebas/mspp/leave/65-compassionate-leave.html">clause 65.6</a>);</p><p><strong>(e)</strong> absences on defence leave (<a href="/eba/ebas/nurses-midwives/leave/72-absences-on-defence-leave.html">clause 72</a>);</p><p><strong>(f)</strong> professional development leave (<a href="/eba/ebas/nurses-midwives/education-pd/75-professional-development-leave.html">clause 75</a>) other than <a href="/eba/ebas/nurses-midwives/education-pd/75-professional-development-leave.html">clause 75.8</a> (mandatory training) which does apply to casual Employees;</p><p><strong>(g)</strong> study leave (<a href="/eba/ebas/nurses-midwives/education-pd/76-study-leave.html">clause 76</a>);</p><p><strong>(h)</strong> examination leave (<a href="/eba/ebas/nurses-midwives/education-pd/77-examination-leave.html">clause 77</a>);</p><p><strong>(i)</strong> rosters (<a href="/eba/ebas/nurses-midwives/hours-of-work/45-rosters.html">clause 45</a>);</p><p><strong>(j)</strong> notice period before termination (<a href="/eba/ebas/nurses-midwives/employment-types/23-notice-period-before-termination.html">clause 23</a>); and</p><p><strong>(k)</strong> special disaster leave (<a href="/eba/ebas/nurses-midwives/leave/72B-special-disaster-leave.html">clause 72B</a>).</p><p><strong>19.8</strong> A casual Employee is entitled to the following:</p><p><strong>(a)</strong> unpaid personal leave for carer&#39;s responsibilities (<a href="/eba/ebas/nurses-midwives/leave/62-casual-employment-caring-responsibilities.html">clause 62</a>);</p><p><strong>(b)</strong> paid family violence leave (<a href="/eba/ebas/nurses-midwives/leave/64-family-and-domestic-violence-leave.html">clause 64</a>);</p><p><strong>(c)</strong> unpaid compassionate leave (<a href="/eba/ebas/mspp/leave/65-compassionate-leave.html">clause 65.9</a>);</p><p><strong>(d)</strong> unpaid pre-adoption leave (<a href="/eba/ebas/nurses-midwives/leave/67-pre-adoption-leave.html">clause 67</a>);</p><p><strong>(e)</strong> parental leave (<a href="/eba/ebas/nurses-midwives/leave/68-parental-leave.html">clause 68</a>) subject to the eligibility requirements of that clause; and</p><p><strong>(f)</strong> unpaid ceremonial leave (<a href="/eba/ebas/nurses-midwives/leave/73-cultural-and-ceremonial-leave.html">clause 73</a>).</p><p>Plain language terms: casuals, casual work, casual rate.</p>',40)])])}const d=a(n,[["render",r]]);export{u as __pageData,d as default};
